const body = $json.body ?? {};
const onlyDigits = (value) => String(value ?? '').replace(/\D/g, '');
const normalizeBrazilPhone = (value) => {
  const digits = onlyDigits(value);
  if (digits.length === 10 || digits.length === 11) return `55${digits}`;
  return digits;
};
const chatId = String(body.chat_id ?? body.from ?? body.customer_phone ?? '').replace(/\s+/g, '').trim();
const msg = String(body.text ?? body.message ?? '').replace(/\s+/g, ' ').trim();
return {
  tenant_id: body.tenant_id || null,
  tenant_phone_e164: normalizeBrazilPhone(body.tenant_phone_e164 ?? body.to ?? body.receiver ?? ''),
  customer_phone_e164: normalizeBrazilPhone(body.customer_phone_e164 ?? body.from ?? body.chat_id ?? ''),
  chat_id: chatId,
  msg,
  raw_body: body
};

const row = Array.isArray($json) ? $json[0] : $json;
const msg = String($node.Normalize.json.msg ?? '').trim();
const customerPhone = String($node.Normalize.json.customer_phone_e164 ?? '').trim();
const payload = row.payload_draft ?? {};
const draft = payload.appointment ?? {};
const appointmentSettings = payload.appointment_settings ?? {};
const services = Array.isArray(row.services) ? row.services : [];
const staff = Array.isArray(row.staff_members) ? row.staff_members : [];
const resources = Array.isArray(row.bookable_resources) ? row.bookable_resources : [];
const upcomingAppointments = Array.isArray(row.upcoming_appointments) ? row.upcoming_appointments : [];
const step = row.step || 'appointment_welcome';
const tenantName = row.tenant_name || 'nossa equipe';

function reply(text, nextStep, patch = {}, close = false) {
  return [{ json: { action: 'patch', reply: text, conversation_id: row.conversation_id, next_step: nextStep, p_close: close, data_patch: { appointment: { ...patch, customer_whatsapp: customerPhone || draft.customer_whatsapp || null }, metadata: { last_step: nextStep, updated_at: new Date().toISOString() } } } }];
}

function suggestSlots(nextStep, patch = {}) {
  const merged = { ...draft, ...patch };
  const isResource = merged.booking_mode === 'resource';
  const common = {
    p_tenant_id: row.tenant_id,
    p_from_date: merged.from_date || new Date().toLocaleDateString('en-CA', { timeZone: 'America/Fortaleza' }),
    p_period: merged.period || null,
    p_limit: 5,
    p_offset: Number(merged.slot_offset || 0),
    p_days_ahead: 60,
    p_timezone: 'America/Fortaleza'
  };
  const suggestBody = isResource
    ? { ...common, p_bookable_resource_id: merged.bookable_resource_id }
    : { ...common, p_service_id: merged.service_id, p_staff_member_id: merged.staff_member_id || null };
  return [{ json: { action: 'suggest_slots', booking_mode: isResource ? 'resource' : 'service', conversation_id: row.conversation_id, next_step: nextStep, p_close: false, data_patch: { appointment: { ...merged, customer_whatsapp: customerPhone || draft.customer_whatsapp || null }, metadata: { last_step: nextStep, updated_at: new Date().toISOString() } }, suggest_body: suggestBody } }];
}

function createAppointment() {
  const isResource = draft.booking_mode === 'resource';
  if (isResource) {
    const resource = resources.find((item) => item.id === draft.bookable_resource_id) ?? null;
    return [{ json: { action: 'create', booking_mode: 'resource', conversation_id: row.conversation_id, next_step: 'appointment_done', p_close: true, create_body: { p_tenant_id: row.tenant_id, p_full_name: draft.full_name, p_cpf: draft.cpf, p_whatsapp_e164: customerPhone || draft.customer_whatsapp, p_birth_date: draft.birth_date, p_bookable_resource_id: draft.bookable_resource_id, p_starts_at: draft.starts_at, p_ends_at: draft.ends_at, p_title: resource ? 'Aluguel de ' + resource.name : 'Aluguel via WhatsApp', p_notes: 'Criado via WhatsApp.' } } }];
  }
  const service = services.find((item) => item.id === draft.service_id) ?? null;
  const staffMember = staff.find((item) => item.id === draft.staff_member_id) ?? null;
  return [{ json: { action: 'create', booking_mode: 'service', conversation_id: row.conversation_id, next_step: 'appointment_done', p_close: true, create_body: { p_tenant_id: row.tenant_id, p_full_name: draft.full_name, p_cpf: draft.cpf, p_whatsapp_e164: customerPhone || draft.customer_whatsapp, p_birth_date: draft.birth_date, p_service_id: draft.service_id || null, p_staff_member_id: draft.staff_member_id || null, p_starts_at: draft.starts_at, p_ends_at: draft.ends_at, p_title: service ? service.name : 'Agendamento via WhatsApp', p_notes: 'Criado via WhatsApp' + (staffMember ? ' com ' + staffMember.name : '') + '.' } } }];
}

function applyAppointmentAction(action, patch = {}) {
  const merged = { ...draft, ...patch };
  return [{ json: { action: 'apply_action', conversation_id: row.conversation_id, next_step: action === 'reschedule' ? 'appointment_rescheduled' : action === 'cancel' ? 'appointment_cancelled' : 'appointment_confirmed', p_close: true, applied_action: action, apply_body: { p_appointment_id: merged.appointment_id, p_action: action, p_new_starts_at: merged.starts_at || null, p_new_ends_at: merged.ends_at || null, p_note: 'Alteracao solicitada pelo cliente via WhatsApp.' }, data_patch: { appointment: { ...merged, customer_whatsapp: customerPhone || draft.customer_whatsapp || null, last_action: action }, metadata: { last_step: 'appointment_done', updated_at: new Date().toISOString() } } } }];
}

function parseCpf(value) {
  const cpf = String(value ?? '').replace(/\D/g, '');
  if (cpf.length !== 11 || /^(\d)\1{10}$/.test(cpf)) return null;
  return cpf;
}

function parseDateBR(value) {
  const match = String(value ?? '').trim().match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})$/);
  if (!match) return null;
  const iso = match[3] + '-' + match[2].padStart(2, '0') + '-' + match[1].padStart(2, '0');
  const date = new Date(iso + 'T00:00:00-03:00');
  if (Number.isNaN(date.getTime())) return null;
  return iso;
}

function timeToMinutes(value, fallback) {
  const match = String(value ?? '').match(/^(\d{1,2}):(\d{2})/);
  if (!match) return fallback;
  return Number(match[1]) * 60 + Number(match[2]);
}

function localNow() {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone: 'America/Fortaleza',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    hourCycle: 'h23'
  }).formatToParts(new Date());
  const value = (type) => parts.find((part) => part.type === type)?.value || '';
  return {
    date: value('year') + '-' + value('month') + '-' + value('day'),
    minutes: Number(value('hour')) * 60 + Number(value('minute'))
  };
}

function availablePeriods() {
  const opensAt = timeToMinutes(appointmentSettings.opens_at, 8 * 60);
  const closesAt = timeToMinutes(appointmentSettings.closes_at, 18 * 60);
  const now = localNow();
  const requestedDate = draft.from_date || now.date;
  const isToday = requestedDate === now.date;
  const periods = [];
  if (opensAt < 720 && closesAt > 480) {
    periods.push({ key: 'morning', label: isToday && now.minutes >= 720 ? 'Manh\u00e3 (pr\u00f3x. dia)' : 'Manh\u00e3', aliases: ['manha', 'morning'] });
  }
  if (opensAt < 1080 && closesAt > 720) {
    periods.push({ key: 'afternoon', label: isToday && now.minutes >= 1080 ? 'Tarde (pr\u00f3x. dia)' : 'Tarde', aliases: ['tarde', 'afternoon'] });
  }
  if (closesAt > 1080) {
    periods.push({ key: 'night', label: isToday && now.minutes >= closesAt ? 'Noite (pr\u00f3x. dia)' : 'Noite', aliases: ['noite', 'night'] });
  }
  periods.push({ key: 'any', label: 'Primeiro livre', aliases: ['qualquer', 'primeiro', 'primeiro horario', 'primeiro horario livre', 'any'] });
  return periods;
}

function periodFromMessage(value) {
  const normalized = String(value ?? '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();
  const periods = availablePeriods();
  const index = Number(normalized) - 1;
  if (Number.isInteger(index) && periods[index]) return { key: periods[index].key, label: periods[index].label.toLowerCase() };
  const selected = periods.find((period) => period.aliases.includes(normalized));
  return selected ? { key: selected.key, label: selected.label.toLowerCase() } : null;
}

function renderServiceMenu() {
  if (!services.length) return 'Ainda não há serviços cadastrados para este estabelecimento. Fale com a equipe para configurar a agenda.';
  return 'Escolha o serviço:\n' + services.map((service, index) => String(index + 1) + ') ' + service.name + (service.duration_minutes ? ' - ' + service.duration_minutes + 'min' : '')).join('\n');
}

function staffForService(serviceId) {
  const service = services.find((item) => item.id === serviceId) ?? null;
  const linkedIds = Array.isArray(service?.staff_member_ids) ? service.staff_member_ids : [];
  return staff.filter((member) => linkedIds.includes(member.id));
}

function renderStaffMenu(candidates = staffForService(draft.service_id)) {
  if (!candidates.length) return 'Ainda não há profissionais vinculados a este serviço. Fale com a equipe para configurar a agenda.';
  return 'Escolha o profissional:\n' + candidates.map((member, index) => String(index + 1) + ') ' + member.name).join('\n');
}

function continueAfterServiceSelection(selected, baseDraft) {
  const candidates = staffForService(selected.id);
  const nextDraft = { ...baseDraft, service_id: selected.id, service_name: selected.name, duration_minutes: selected.duration_minutes };
  if (!candidates.length) return reply(renderStaffMenu(candidates), 'choose_service', draft);
  if (candidates.length === 1) {
    const only = candidates[0];
    return reply(renderPeriodMenu(), 'choose_period', { ...nextDraft, staff_member_id: only.id, staff_member_name: only.name, slot_offset: 0 });
  }
  return reply(renderStaffMenu(candidates), 'choose_staff', nextDraft);
}

function renderBookingModeMenu() {
  return 'O que você deseja agendar?\n1) Serviço ou profissional\n2) Alugar quadra ou ambiente';
}

function renderResourceMenu() {
  if (!resources.length) return 'Ainda não há quadras ou ambientes cadastrados. Fale com a equipe para configurar os locais.';
  return 'Escolha a quadra ou ambiente:\n' + resources.map((resource, index) => String(index + 1) + ') ' + resource.name + (resource.duration_minutes ? ' - ' + resource.duration_minutes + 'min' : '') + (Number.isFinite(resource.price_cents) ? ' - R$ ' + (resource.price_cents / 100).toFixed(2).replace('.', ',') : '')).join('\n');
}

function continueAfterResourceSelection(selected, baseDraft) {
  return reply(renderPeriodMenu(), 'choose_period', { ...baseDraft, booking_mode: 'resource', bookable_resource_id: selected.id, bookable_resource_name: selected.name, duration_minutes: selected.duration_minutes, service_id: null, staff_member_id: null, slot_offset: 0 });
}

function renderPeriodMenu(prefix = 'Qual per\u00edodo voc\u00ea prefere?') {
  const lines = availablePeriods().map((period, index) => String(index + 1) + ') ' + period.label);
  return prefix + '\n' + lines.join('\n');
}

function pickSlot(value) {
  const index = Number(value) - 1;
  const slots = Array.isArray(draft.available_slots) ? draft.available_slots : [];
  return slots[index] ?? null;
}

function normalizeAction(value) {
  return String(value ?? '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();
}

function renderMainMenu(welcome = '') {
  const prefix = welcome ? welcome + '\n\n' : '';
  return prefix + 'O que deseja fazer?\n1) Agendar\n2) Remarcar agendamento\n3) Cancelar agendamento';
}

function renderExistingAppointmentMenu(actionLabel) {
  if (!upcomingAppointments.length) return 'Não encontrei agendamentos futuros para este WhatsApp. Fale com a equipe para ' + actionLabel + '.';
  return 'Escolha qual agendamento deseja ' + actionLabel + ':\n' + upcomingAppointments.map((appointment, index) => String(index + 1) + ') ' + appointment.label).join('\n');
}

function pickExistingAppointment(value) {
  const index = Number(value) - 1;
  return upcomingAppointments[index] ?? null;
}

function actionFromMessage(value) {
  const normalized = normalizeAction(value);
  if (['1', 'agendar', 'agenda', 'marcar', 'novo', 'novo agendamento'].includes(normalized)) return 'schedule';
  if (['2', 'remarcar', 'reagendar', 'mudar horario', 'alterar'].includes(normalized)) return 'reschedule';
  if (['3', 'cancelar', 'cancelamento', 'desmarcar'].includes(normalized)) return 'cancel';
  return null;
}

function startExistingAppointmentAction(action) {
  const actionLabel = action === 'cancel' ? 'cancelar' : 'remarcar';
  if (!upcomingAppointments.length) return reply('Não encontrei agendamentos futuros para este WhatsApp. Fale com a equipe para ' + actionLabel + '.', 'appointment_done', draft, true);
  if (upcomingAppointments.length === 1) {
    const appointment = upcomingAppointments[0];
    return reply('Para ' + actionLabel + ' este agendamento, confirme sua data de nascimento no formato DD/MM/AAAA.\n\n' + appointment.label, 'confirm_existing_appointment_identity', { ...draft, pending_action: action, appointment_id: appointment.appointment_id, customer_birth_date: appointment.customer_birth_date, service_id: appointment.service_id, service_name: appointment.service_name, staff_member_id: appointment.staff_member_id, staff_member_name: appointment.staff_member_name, duration_minutes: appointment.duration_minutes, booking_mode: appointment.bookable_resource_id ? 'resource' : 'service', bookable_resource_id: appointment.bookable_resource_id || null, bookable_resource_name: appointment.bookable_resource_name || null, slot_offset: 0 });
  }
  return reply(renderExistingAppointmentMenu(actionLabel), 'choose_existing_appointment', { ...draft, pending_action: action });
}

if (!msg && step !== 'appointment_welcome') return reply('Não recebi nenhuma mensagem. Pode enviar novamente?', step, draft);

if (step === 'appointment_confirmation_action') {
  const normalized = msg.toLowerCase();
  if (['1', 'confirmar', 'confirmo', 'sim', 's'].includes(normalized)) return applyAppointmentAction('confirm');
  if (['3', 'cancelar', 'cancela'].includes(normalized)) return applyAppointmentAction('cancel');
  if (['2', 'remarcar'].includes(normalized)) return reply('Claro. Para remarcar, confirme sua data de nascimento no formato DD/MM/AAAA.', 'reschedule_confirm_identity', { ...draft, reschedule: true, slot_offset: 0 });
  return reply('Como você deseja seguir?\n1) Confirmar\n2) Remarcar\n3) Cancelar', step, draft);
}

if (['menu', '0', 'inicio', 'iniciar'].includes(normalizeAction(msg)) || step === 'appointment_welcome') {
  const welcome = String(row.welcome_message || '').replaceAll('{{tenant_name}}', tenantName);
  return reply(renderMainMenu(welcome), 'choose_appointment_action', {});
}

if (step === 'choose_appointment_action') {
  const action = actionFromMessage(msg);
  if (!action) return reply(renderMainMenu('Não entendi sua escolha.'), step, draft);
  if (action === 'schedule') return reply('Perfeito. Para começar, envie seu nome completo.', 'collect_full_name', draft);
  return startExistingAppointmentAction(action);
}

if (step === 'choose_existing_appointment') {
  const appointment = pickExistingAppointment(msg);
  const action = draft.pending_action === 'cancel' ? 'cancel' : 'reschedule';
  const actionLabel = action === 'cancel' ? 'cancelar' : 'remarcar';
  if (!appointment) return reply(renderExistingAppointmentMenu(actionLabel), step, draft);
  return reply('Para ' + actionLabel + ' este agendamento, confirme sua data de nascimento no formato DD/MM/AAAA.\n\n' + appointment.label, 'confirm_existing_appointment_identity', { ...draft, pending_action: action, appointment_id: appointment.appointment_id, customer_birth_date: appointment.customer_birth_date, service_id: appointment.service_id, service_name: appointment.service_name, staff_member_id: appointment.staff_member_id, staff_member_name: appointment.staff_member_name, duration_minutes: appointment.duration_minutes, booking_mode: appointment.bookable_resource_id ? 'resource' : 'service', bookable_resource_id: appointment.bookable_resource_id || null, bookable_resource_name: appointment.bookable_resource_name || null, slot_offset: 0 });
}

if (step === 'confirm_existing_appointment_identity') {
  const birthDate = parseDateBR(msg);
  if (!birthDate) return reply('Data inválida. Envie no formato DD/MM/AAAA para confirmar sua identidade.', step, draft);
  if (draft.customer_birth_date && birthDate !== draft.customer_birth_date) {
    return reply('Não consegui confirmar sua identidade. Fale com a equipe para alterar este agendamento.', 'appointment_done', draft, true);
  }
  if (draft.pending_action === 'cancel') return applyAppointmentAction('cancel', draft);
  return reply(renderPeriodMenu('Identidade confirmada. Para remarcar, escolha um periodo:'), 'reschedule_choose_period', { ...draft, identity_confirmed: true });
}

if (step === 'collect_full_name') {
  const name = msg.replace(/\s+/g, ' ').trim();
  if (name.split(' ').filter(Boolean).length < 2) return reply('Informe seu nome completo, por favor. Ex.: João Silva.', step, draft);
  return reply('Perfeito. Agora envie seu CPF com 11 dígitos.', 'collect_cpf', { ...draft, full_name: name });
}

if (step === 'collect_cpf') {
  const cpf = parseCpf(msg);
  if (!cpf) return reply('CPF inválido. Envie apenas os 11 dígitos.', step, draft);
  return reply('Agora envie sua data de nascimento no formato DD/MM/AAAA.', 'collect_birth_date', { ...draft, cpf });
}

if (step === 'collect_birth_date') {
  const birthDate = parseDateBR(msg);
  if (!birthDate) return reply('Data inválida. Envie no formato DD/MM/AAAA.', step, draft);
  const nextDraft = { ...draft, birth_date: birthDate };
  if (resources.length && services.length) return reply(renderBookingModeMenu(), 'choose_booking_mode', nextDraft);
  if (resources.length === 1) return continueAfterResourceSelection(resources[0], nextDraft);
  if (resources.length > 1) return reply(renderResourceMenu(), 'choose_resource', nextDraft);
  if (services.length === 1) return continueAfterServiceSelection(services[0], nextDraft);
  return reply(renderServiceMenu(), 'choose_service', nextDraft);
}

if (step === 'reschedule_confirm_identity') {
  const birthDate = parseDateBR(msg);
  if (!birthDate) return reply('Data inválida. Envie no formato DD/MM/AAAA para confirmar sua identidade.', step, draft);
  if (draft.customer_birth_date && birthDate !== draft.customer_birth_date) {
    return reply('Não consegui confirmar sua identidade. Fale com a equipe para remarcar este horário.', 'appointment_done', draft, true);
  }
  return reply(renderPeriodMenu('Identidade confirmada. Para remarcar, escolha um periodo:'), 'reschedule_choose_period', { ...draft, identity_confirmed: true });
}

if (step === 'choose_booking_mode') {
  const normalized = normalizeAction(msg);
  if (['1', 'servico', 'serviço', 'profissional', 'atendimento'].includes(normalized)) {
    if (services.length === 1) return continueAfterServiceSelection(services[0], { ...draft, booking_mode: 'service' });
    return reply(renderServiceMenu(), 'choose_service', { ...draft, booking_mode: 'service' });
  }
  if (['2', 'alugar', 'aluguel', 'quadra', 'ambiente'].includes(normalized)) {
    if (resources.length === 1) return continueAfterResourceSelection(resources[0], draft);
    return reply(renderResourceMenu(), 'choose_resource', draft);
  }
  return reply(renderBookingModeMenu(), step, draft);
}

if (step === 'choose_resource') {
  const selected = resources[Number(msg) - 1];
  if (!selected) return reply(renderResourceMenu(), step, draft);
  return continueAfterResourceSelection(selected, draft);
}

if (step === 'choose_service') {
  if (!services.length) return reply(renderServiceMenu(), step, draft);
  const selected = services[Number(msg) - 1];
  if (!selected) return reply(renderServiceMenu(), step, draft);
  return continueAfterServiceSelection(selected, draft);
}

if (step === 'choose_staff') {
  const candidates = staffForService(draft.service_id);
  const selected = candidates[Number(msg) - 1];
  if (!selected) return reply(renderStaffMenu(candidates), step, draft);
  return reply(renderPeriodMenu(), 'choose_period', { ...draft, staff_member_id: selected.id, staff_member_name: selected.name, slot_offset: 0 });
}

if (step === 'choose_period' || step === 'reschedule_choose_period') {
  const period = periodFromMessage(msg);
  if (!period) return reply(renderPeriodMenu('Não entendi. Escolha um período:'), step, draft);
  const nextStep = step === 'reschedule_choose_period' ? 'reschedule_select_slot' : 'select_slot';
  return suggestSlots(nextStep, { ...draft, period: period.key, period_label: period.label, slot_offset: 0 });
}

if (step === 'select_slot' || step === 'reschedule_select_slot') {
  const normalized = msg.toLowerCase();
  if (['mais', 'mais opcoes', 'mais opcoes', 'm'].includes(normalized)) {
    const currentSlots = Array.isArray(draft.available_slots) ? draft.available_slots : [];
    return suggestSlots(step, { ...draft, slot_offset: Number(draft.slot_offset || 0) + currentSlots.length });
  }
  const slot = pickSlot(msg);
  if (!slot) return reply('Escolha uma das opções ou toque em *Ver mais horários*.', step, draft);
  if (step === 'reschedule_select_slot') {
    return applyAppointmentAction('reschedule', { ...draft, starts_at: slot.starts_at, ends_at: slot.ends_at, staff_member_id: slot.staff_member_id || draft.staff_member_id || null, staff_member_name: slot.staff_member_name || draft.staff_member_name || null });
  }
  const summary = draft.booking_mode === 'resource' ? 'Confirme seu aluguel:\n\nNome: ' + draft.full_name + '\nLocal: ' + (draft.bookable_resource_name || '-') + '\nHorário: ' + slot.label + '\n\nConfira os dados e escolha uma das opções abaixo.' : 'Confirme seu agendamento:\n\nNome: ' + draft.full_name + '\nServiço: ' + (draft.service_name || '-') + '\nProfissional: ' + (slot.staff_member_name || draft.staff_member_name || 'Sem preferência') + '\nHorário: ' + slot.label + '\n\nConfira os dados e escolha uma das opções abaixo.';
  return reply(summary, 'confirm_appointment', { ...draft, starts_at: slot.starts_at, ends_at: slot.ends_at, staff_member_id: slot.staff_member_id || draft.staff_member_id || null, staff_member_name: slot.staff_member_name || draft.staff_member_name || null, selected_slot_label: slot.label });
}

if (step === 'confirm_appointment') {
  if (!['sim', 's', 'confirmar', 'confirmo'].includes(msg.toLowerCase())) return reply('Confirme seu agendamento:\n\nAinda preciso da sua confirmação. Escolha uma das opções abaixo.', step, draft);
  return createAppointment();
}

return reply('Vamos recomecar. Me informe seu nome completo.', 'collect_full_name', {});

const appointmentId = $json.data ?? $json.body ?? $json;
return [{ json: {
  reply: 'Agendamento confirmado! Se precisar ajustar este horário ou marcar outro, use o botão Agendamentos abaixo.',
  conversation_id: $node.FN_appointment_state_machine.json.conversation_id,
  next_step: 'appointment_created',
  p_close: true,
  data_patch: {
    appointment: {
      appointment_id: Array.isArray(appointmentId) ? appointmentId[0] : appointmentId,
      last_action: 'create'
    },
    metadata: {
      completed_at: new Date().toISOString()
    }
  }
}}];

const inputItems = typeof $input !== 'undefined' ? $input.all().map((item) => item.json) : [$json];
const minimumStart = Date.now() + 60 * 1000;
const slots = inputItems.filter((item) => item && item.starts_at && item.ends_at && new Date(item.starts_at).getTime() > minimumStart);
const original = $node.FN_appointment_state_machine.json;
const previousPatch = original.data_patch?.appointment ?? {};
const nextStep = original.next_step;
if (!slots.length) {
  return [{ json: { action: 'patch', reply: 'Não encontrei horários livres nesse período. Toque em *Ver mais horários* ou volte ao menu de agendamentos.', conversation_id: original.conversation_id, next_step: nextStep, p_close: false, data_patch: original.data_patch } }];
}
const lines = slots.map((slot, index) => String(index + 1) + ') ' + slot.label);
